function putText(n,s){const repo=process.env.GH_REPO,tok=process.env.GH_TOKEN;const url='https://api.github.com/repos/'+repo+'/contents/analize/'+n;let sha='';try{sha=JSON.parse(execSync('curl -s --max-time 30 -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||'';}catch(e){}const b={message:'x',branch:'main',content:Buffer.from(s,'utf8').toString('base64')};if(sha)b.sha=sha;fs.writeFileSync('/tmp/pf.json',JSON.stringify(b));execSync('curl -s --max-time 40 -X PUT -H "Authorization: Bearer '+tok+'" -d @/tmp/pf.json "'+url+'"',{encoding:'utf8'});}
const BASE='https://dev.avesa.lt';const U=process.env.WP_USER||'';const P=(process.env.WP_APP_PASS||'').replace(/\s+/g,'');
const TESTPHP="if ( ! defined('ABSPATH') ) { return; }\nadd_action('wp_loaded', function(){\n  if ( ! isset($_GET['ps_content_test']) ) { return; }\n  if ( ($_GET['token']??'') !== 'cmplz_6680aa2a42151d54fa8d64ec' ) { return; }\n  $out = array();\n  global $wpdb;\n\n  $out['0_ver'] = defined('PETSHOP_CORE_VERSION') ? PETSHOP_CORE_VERSION : '?';\n  $out['0_class'] = class_exists('Petshop_Pet_Content');\n  $out['0_json'] = file_exists(WP_PLUGIN_DIR.'/petshop-core/data/aktualu_siandien.json');\n\n  $uid = wp_create_user('ps_content_test', wp_generate_password(), 'terra@gyvunai.lt');\n  if(is_wp_error($uid)){ $u=get_user_by('email','terra@gyvunai.lt'); $uid=$u->ID; }\n  wp_set_current_user($uid);\n  $wpdb->query($wpdb->prepare(\"DELETE FROM {$wpdb->prefix}ps_pets WHERE user_id=%d\", $uid));\n  // Isvalom sena content_seen meta\n  foreach($wpdb->get_col($wpdb->prepare(\"SELECT meta_key FROM {$wpdb->usermeta} WHERE user_id=%d AND meta_key LIKE 'ps_content_seen_%'\", $uid)) as $mk){\n    delete_user_meta($uid, $mk);\n  }\n\n  // Pagalbine: sukurti augintini\n  $mkpet = function($species, $need=null, $stage=null, $steril=null) use ($uid, $wpdb){\n    $req = new WP_REST_Request('POST', '/petshop/v1/pet-profile');\n    $req->set_param('species', $species);\n    $req->set_param('pet_name', 'Test');\n    if($need) $req->set_param('primary_need', $need);\n    if($stage) $req->set_param('life_stage', $stage);\n    if($steril) $req->set_param('is_sterilised', $steril);\n    return rest_do_request($req)->get_data()['pet_id'];\n  };\n\n  // TEST 1: suo be poreikio \u2014 turi gauti bendra suns turini (pvz erkes jei sezonas, ar food_transition)\n  $dog = $mkpet('dog');\n  $c1 = rest_do_request(new WP_REST_Request('GET', '/petshop/v1/pet-content/'.$dog))->get_data();\n  $out['1_dog_content'] = $c1['content']['id'] ?? 'null';\n\n  // TEST 2: skin_allergy poreikis \u2014 turi gauti skin_allergy_care (prio 80) jei ne cooldown\n  //   Bet pirma isvalom seen kad nekonfliktuotu\n  foreach($wpdb->get_col($wpdb->prepare(\"SELECT meta_key FROM {$wpdb->usermeta} WHERE user_id=%d AND meta_key LIKE 'ps_content_seen_%'\", $uid)) as $mk){ delete_user_meta($uid, $mk); }\n  $dog2 = $mkpet('dog', 'skin_allergy');\n  $c2 = rest_do_request(new WP_REST_Request('GET', '/petshop/v1/pet-content/'.$dog2))->get_data();\n  $out['2_skin_allergy'] = $c2['content']['id'] ?? 'null';\n\n  // TEST 3: fish \u2014 turi gauti fish_water_change (arba habitat? ne, fish tik fish_water)\n  foreach($wpdb->get_col($wpdb->prepare(\"SELECT meta_key FROM {$wpdb->usermeta} WHERE user_id=%d AND meta_key LIKE 'ps_content_seen_%'\", $uid)) as $mk){ delete_user_meta($uid, $mk); }\n  $fish = $mkpet('fish');\n  $c3 = rest_do_request(new WP_REST_Request('GET', '/petshop/v1/pet-content/'.$fish))->get_data();\n  $out['3_fish'] = $c3['content']['id'] ?? 'null';\n\n  // TEST 4: sterilizuota kate \u2014 sterilised_diet TIK jei is_sterilised=yes\n  foreach($wpdb->get_col($wpdb->prepare(\"SELECT meta_key FROM {$wpdb->usermeta} WHERE user_id=%d AND meta_key LIKE 'ps_content_seen_%'\", $uid)) as $mk){ delete_user_meta($uid, $mk); }\n  $cat_st = $mkpet('cat', null, null, 'yes');\n  // Reflection: tiesiogiai testuojam select_for_pet kad matytume ar sterilised_diet kandidatas\n  $pet_obj = Petshop_Pet_Profile::get_pet($cat_st);\n  $item = Petshop_Pet_Content::select_for_pet($uid, $pet_obj);\n  $out['4_cat_sterilised_top'] = $item['id'] ?? 'null';\n\n  // TEST 5: NEsterilizuota kate \u2014 sterilised_diet NETURI buti\n  foreach($wpdb->get_col($wpdb->prepare(\"SELECT meta_key FROM {$wpdb->usermeta} WHERE user_id=%d AND meta_key LIKE 'ps_content_seen_%'\", $uid)) as $mk){ delete_user_meta($uid, $mk); }\n  $cat_no = $mkpet('cat', null, null, 'no');\n  // Pilnas skanavimas: ar sterilised_diet tarp galimu? Tikrinam kad NE\n  //   Rankiniu budu: sukuriam meta visiems KITIEMS kad liktu tik sterilised jei jis tiktu\n  $pet_obj2 = Petshop_Pet_Profile::get_pet($cat_no);\n  // Uzblokuojam visus kitus per cooldown isskyrus sterilised\n  $all_ids = array('tick_season','summer_water','food_transition','sensitive_digestion','skin_allergy_care','picky_eater','senior_care','travel_pets','fireworks_stress','habitat_care');\n  foreach($all_ids as $bid){ update_user_meta($uid, 'ps_content_seen_'.$bid, gmdate('Y-m-d H:i:s')); }\n  $item2 = Petshop_Pet_Content::select_for_pet($uid, $pet_obj2);\n  $out['5_cat_not_steril'] = $item2 ? $item2['id'] : 'null (teisingai \u2014 sterilised NErodomas)';\n\n  // TEST 6: cooldown \u2014 po rodymo tas pats iskart neturi kartotis\n  foreach($wpdb->get_col($wpdb->prepare(\"SELECT meta_key FROM {$wpdb->usermeta} WHERE user_id=%d AND meta_key LIKE 'ps_content_seen_%'\", $uid)) as $mk){ delete_user_meta($uid, $mk); }\n  $dog3 = $mkpet('dog', 'digestion');\n  $first = rest_do_request(new WP_REST_Request('GET', '/petshop/v1/pet-content/'.$dog3))->get_data();\n  $first_id = $first['content']['id'] ?? 'null';\n  $second = rest_do_request(new WP_REST_Request('GET', '/petshop/v1/pet-content/'.$dog3))->get_data();\n  $second_id = $second['content']['id'] ?? 'null';\n  $out['6_cooldown'] = array('first'=>$first_id, 'second'=>$second_id, 'skirtingi'=>($first_id !== $second_id ? 'TAIP (cooldown veikia)' : 'NE'));\n\n  // TEST 7: sezono per-metu-riba (fireworks 12-20 -> 01-05)\n  //   Testuojam season_ok logika per data\n  $test_dates = array('12-25'=>true, '01-03'=>true, '06-15'=>false, '11-01'=>false);\n  $rm = new ReflectionMethod('Petshop_Pet_Content', 'season_ok');\n  $rm->setAccessible(true);\n  $fw_item = array('season_start'=>'12-20', 'season_end'=>'01-05');\n  $season_results = array();\n  foreach($test_dates as $date=>$expected){\n    $dt = new DateTime('2026-'.$date, new DateTimeZone('UTC'));\n    $got = $rm->invoke(null, $fw_item, $dt);\n    $season_results[$date] = ($got === $expected) ? 'OK' : ('BLOGAI (got '.var_export($got,true).')');\n  }\n  $out['7_season_wrap'] = $season_results;\n\n  // cleanup\n  $wpdb->query($wpdb->prepare(\"DELETE FROM {$wpdb->prefix}ps_pets WHERE user_id=%d\", $uid));\n  foreach($wpdb->get_col($wpdb->prepare(\"SELECT meta_key FROM {$wpdb->usermeta} WHERE user_id=%d AND meta_key LIKE 'ps_content_seen_%'\", $uid)) as $mk){ delete_user_meta($uid, $mk); }\n  require_once ABSPATH.'wp-admin/includes/user.php';\n  $u=get_user_by('login','ps_content_test'); if($u) wp_delete_user($u->ID);\n  $out['9_cleanup']='done';\n\n  header('Content-Type: application/json; charset=utf-8');\n  echo wp_json_encode($out, JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES|JSON_PRETTY_PRINT);\n  exit;\n}, 6);";const F={"main": "", "content": "", "contentjson": "", "profilejs": "", "css": ""};
function api(method,path,body){const auth='-u "'+U+':'+P+'"';let cmd;if(body){fs.writeFileSync('/tmp/b.json',JSON.stringify(body));cmd='curl -s -k -A "Mozilla/5.0" --max-time 90 '+auth+' -X '+method+' -H "Content-Type: application/json" --data-binary @/tmp/b.json "'+BASE+path+'"';}else{cmd='curl -s -k -A "Mozilla/5.0" --max-time 60 '+auth+' -X '+method+' "'+BASE+path+'"';}let r;try{r=execSync(cmd,{encoding:'utf8',maxBuffer:30000000});}catch(e){r=(e.stdout||'');}return r;}
